class Solution {
public:
    vector<int> memLeak(int memory1, int memory2) {
        int time = 1;
        while (true) {
            if (memory1 >= time && memory2 >= time) {
                if (memory1 >= memory2) {
                    memory1 -= time;
                } else {
                    memory2 -= time;
                }
            } else if (memory1 >= time) {
                memory1 -= time;
            } else if (memory2 >= time) {
                memory2 -= time;
            } else {
                return {time, memory1, memory2};
            }
            time++;
        }
    }
};
```
